def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0
        temp_ratio = ratio
        for j in range(5):
            if temp_ratio < 0.05:
                score += (0.05 - temp_ratio) ** 3
            elif temp_ratio < 0.3:
                val = (0.3 - temp_ratio)
                score += val * val * 0.7
            elif temp_ratio < 0.7:
                score += np.log1p(temp_ratio * 2)
            else:
                score += np.sqrt(temp_ratio)
            temp_ratio = temp_ratio / (j + 2)
        for _ in range(3):
            if ratio < 0.2:
                score += (0.2 - ratio) * 0.4
            elif ratio < 0.6:
                score += (0.6 - ratio) ** 0.5
            else:
                score += np.log1p(ratio * 1.5)
            ratio = np.sqrt(ratio)
        if score < 0:
            score = abs(score) * 0.5
        if capacity % 2 == 0:
            score *= 0.9
        else:
            score *= 1.1
        if np.isnan(score) or np.isinf(score):
            priorities[i] = np.inf
        else:
            priorities[i] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        max_priority = np.max(priorities[finite_mask])
        for i in range(len(priorities)):
            if not finite_mask[i]:
                priorities[i] = max_priority + np.random.rand()
    else:
        priorities[:] = 1e6
    return priorities
